import React, { useState, useEffect, useContext } from 'react';
import { useNavigate } from 'react-router-dom';
import {
  Container,
  Box,
  Typography,
  Button,
  CircularProgress,
  Alert,
  Dialog,
  DialogTitle,
  DialogContent,
  DialogActions,
  TextField,
  Paper,
  Chip,
} from '@mui/material';
import { Add as AddIcon } from '@mui/icons-material';
import { AuthContext } from '../context/AuthContext';
import api from '../api';
import KanbanBoard from '../components/KanbanBoard';

export default function AdminDashboard() {
  const navigate = useNavigate();
  const { user } = useContext(AuthContext);
  const [tasks, setTasks] = useState([]);
  const [progressions, setProgressions] = useState([]);
  const [selectedProgressionId, setSelectedProgressionId] = useState('default');
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState('');
  const [openDialog, setOpenDialog] = useState(false);
  const [progressionName, setProgressionName] = useState('');
  const [progressionDescription, setProgressionDescription] = useState('');

  const fetchData = async () => {
    setLoading(true);
    try {
      const [proRes, taskRes] = await Promise.all([
        api.get('/task-progressions'),
        api.get('/tasks'),
      ]);

      const progBody = proRes.data;
      const progList = Array.isArray(progBody) ? progBody : (progBody.progressions ?? progBody.data ?? []);
      setProgressions(progList || []);

      const taskBody = taskRes.data;
      const taskList = Array.isArray(taskBody) ? taskBody : (taskBody.tasks ?? taskBody.data ?? []);
      setTasks(taskList || []);

      setError('');
    } catch (err) {
      console.error('Failed to load data', err);
      setError('Failed to load tasks and progressions');
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    fetchData();
  }, []);

  const handleCreateProgression = async () => {
    if (!progressionName.trim()) {
      alert('Please enter a progression name');
      return;
    }
    try {
      await api.post('/task-progressions', {
        name: progressionName,
        description: progressionDescription,
      });
      setProgressionName('');
      setProgressionDescription('');
      setOpenDialog(false);
      await fetchData();
    } catch (err) {
      console.error('Failed to create progression', err);
      alert('Failed to create progression: ' + (err.response?.data?.message || err.message));
    }
  };

  const handleMoveTask = async (taskId, info) => {
    try {
      const column = info.column;
      if (selectedProgressionId === 'default') {
        await api.patch(`/tasks/${taskId}/status`, { status: column });
      } else {
        await api.patch(`/tasks/${taskId}/status`, { task_progression_step_id: column });
      }
      await fetchData();
    } catch (err) {
      console.error('Failed to move task', err);
    }
  };

  const getColumns = () => {
    if (selectedProgressionId === 'default') {
      return [
        { id: null, name: 'To Do', key: 'pending' },
        { id: null, name: 'In Progress', key: 'in_progress' },
        { id: null, name: 'Done', key: 'completed' },
      ];
    }

    const prog = progressions.find((p) => String(p.id) === String(selectedProgressionId));
    return prog?.steps?.sort((a, b) => a.sort_order - b.sort_order) || [];
  };

  const getTasksByColumn = () => {
    const cols = getColumns();

    if (selectedProgressionId === 'default') {
      return {
        'pending': tasks.filter((t) => !t.progression_step && t.status === 'pending'),
        'in_progress': tasks.filter((t) => !t.progression_step && t.status === 'in_progress'),
        'completed': tasks.filter((t) => !t.progression_step && t.status === 'completed'),
      };
    }

    const map = {};
    cols.forEach((c) => (map[c.id] = []));
    tasks
      .filter((t) => String(t.progression?.id) === String(selectedProgressionId))
      .forEach((task) => {
        const key = task.progression_step?.id ?? null;
        if (map[key]) map[key].push(task);
        else if (cols.length > 0) map[cols[0].id].push(task);
      });
    return map;
  };

  return (
    <Box sx={{ backgroundColor: '#F8FAFC', minHeight: 'calc(100vh - 64px)', py: 4 }}>
      <Container maxWidth="xl">
        <Box sx={{ mb: 6 }}>
          <Typography variant="h3" sx={{ fontWeight: 800, mb: 1, color: '#0F172A' }}>
            Task Management
          </Typography>
          <Typography variant="body1" sx={{ color: '#64748B' }}>
            Manage your team's workflow with custom progressions
          </Typography>
        </Box>

        {error && (
          <Alert severity="error" sx={{ mb: 4, borderRadius: 2 }}>
            {error}
          </Alert>
        )}

        {/* Progression Tabs */}
        <Paper
          elevation={0}
          sx={{
            mb: 4,
            p: 2,
            backgroundColor: '#fff',
            border: '1px solid #E2E8F0',
            borderRadius: 2,
            display: 'flex',
            gap: 1,
            alignItems: 'center',
            flexWrap: 'wrap',
          }}
        >
          <Chip
            label="Default"
            onClick={() => setSelectedProgressionId('default')}
            variant={selectedProgressionId === 'default' ? 'filled' : 'outlined'}
            sx={{
              bgcolor: selectedProgressionId === 'default' ? '#06B6D4' : 'transparent',
              color: selectedProgressionId === 'default' ? '#fff' : '#64748B',
              borderColor: '#E2E8F0',
              fontWeight: 600,
            }}
          />
          {progressions.map((prog) => (
            <Chip
              key={prog.id}
              label={prog.name}
              onClick={() => setSelectedProgressionId(String(prog.id))}
              variant={String(selectedProgressionId) === String(prog.id) ? 'filled' : 'outlined'}
              sx={{
                bgcolor: String(selectedProgressionId) === String(prog.id) ? '#06B6D4' : 'transparent',
                color: String(selectedProgressionId) === String(prog.id) ? '#fff' : '#64748B',
                borderColor: '#E2E8F0',
                fontWeight: 600,
              }}
            />
          ))}
          <Box sx={{ flex: 1 }} />
          <Button
            variant="contained"
            startIcon={<AddIcon />}
            onClick={() => setOpenDialog(true)}
            sx={{
              backgroundColor: '#06B6D4',
              '&:hover': { backgroundColor: '#0891B2' },
              textTransform: 'none',
              fontWeight: 600,
            }}
          >
            New Progression
          </Button>
          <Button
            variant="outlined"
            startIcon={<AddIcon />}
            onClick={() => navigate('/admin/create-task')}
            sx={{
              borderColor: '#06B6D4',
              color: '#06B6D4',
              textTransform: 'none',
              fontWeight: 600,
            }}
          >
            Create Task
          </Button>
        </Paper>

        {/* Loading State */}
        {loading ? (
          <Box sx={{ display: 'flex', justifyContent: 'center', py: 8 }}>
            <CircularProgress />
          </Box>
        ) : (
          <Box>
            <KanbanBoard
              columns={getColumns()}
              tasksByColumn={getTasksByColumn()}
              currentUser={user}
              canDragTask={() => true}
              onMoveTask={handleMoveTask}
            />
          </Box>
        )}

        {/* Create Progression Dialog */}
        <Dialog open={openDialog} onClose={() => setOpenDialog(false)} maxWidth="sm" fullWidth>
          <DialogTitle sx={{ fontWeight: 700, fontSize: '1.25rem' }}>
            Create New Progression Type
          </DialogTitle>
          <DialogContent sx={{ pt: 3 }}>
            <TextField
              autoFocus
              fullWidth
              label="Progression Name"
              placeholder="e.g., Bug Fix, QA Testing, Feature Development"
              value={progressionName}
              onChange={(e) => setProgressionName(e.target.value)}
              variant="outlined"
              sx={{ mb: 2 }}
            />
            <TextField
              fullWidth
              label="Description (Optional)"
              placeholder="Describe this progression type..."
              value={progressionDescription}
              onChange={(e) => setProgressionDescription(e.target.value)}
              variant="outlined"
              multiline
              rows={3}
            />
            <Typography variant="caption" sx={{ color: '#94A3B8', mt: 2, display: 'block' }}>
              A default 3-step progression (To Do → In Progress → Done) will be created automatically.
            </Typography>
          </DialogContent>
          <DialogActions sx={{ p: 2 }}>
            <Button onClick={() => setOpenDialog(false)} sx={{ color: '#64748B' }}>
              Cancel
            </Button>
            <Button
              onClick={handleCreateProgression}
              variant="contained"
              sx={{ backgroundColor: '#06B6D4' }}
            >
              Create
            </Button>
          </DialogActions>
        </Dialog>
      </Container>
    </Box>
  );
}
